# Example: tenant isolation assertion in agent runtime
from dataclasses import dataclass
from typing import Any

@dataclass
class AgentContext:
    tenant_id: str
    session_id: str
    user_id: str

def assert_tenant_isolation(ctx: AgentContext, retrieved_docs: list[dict]) -> None:
    """Fail fast if retrieved documents belong to a different tenant."""
    violations = [
        doc for doc in retrieved_docs
        if doc.get("tenant_id") != ctx.tenant_id
    ]
    if violations:
        raise TenantIsolationViolation(
            f"Cross-tenant leak detected: {len(violations)} documents "
            f"from foreign tenant(s) in context for tenant {ctx.tenant_id}"
        )

class TenantIsolationViolation(RuntimeError):
    pass
